``

const items = $input.all();

if (items[0]?.json?._empty) return [];

const apiKey = $env.GOOGLE_MAPS_API_KEY || '';
const enriched = [];

for (const item of items) {
  const lead = { ...item.json };

  if (!lead.place_id) {
    enriched.push({ json: lead }); // keep item
    continue;
  }

  try {
    const url = `https://maps.googleapis.com/maps/api/place/details/json?place_id=${lead.place_id}&fields=website,formatted_phone_number,opening_hours,editorial_summary&key=${apiKey}`;

    const response = await fetch(url);
    const data = await response.json();

    if (data.result) {
      lead.website = data.result.website || '';
      lead.phone = data.result.formatted_phone_number || '';
      lead.opening_hours =
        data.result.opening_hours?.weekday_text?.join(' | ') || '';
      lead.description =
        data.result.editorial_summary?.overview || '';
    }
  } catch (e) {
    // silent fail
  }

  enriched.push({ json: lead });
}

return enriched;

const items = items || .all();
const scored = [];

for (const item of items) {
  const lead = item.json;
  let score = 0;
  let signals = [];

  // Reviews = demand (0-25)
  if (lead.review_count >= 100) { score += 25; signals.push('High demand (100+ reviews)'); }
  else if (lead.review_count >= 50) { score += 20; signals.push('Good demand (50+ reviews)'); }
  else if (lead.review_count >= 20) { score += 15; signals.push('Established (20+ reviews)'); }
  else { score += 10; signals.push('Some reviews'); }

  // Rating = quality (0-15)
  if (lead.rating >= 4.5) { score += 15; signals.push('Excellent rating'); }
  else if (lead.rating >= 4.0) { score += 12; signals.push('Good rating'); }
  else if (lead.rating >= 3.5) { score += 8; signals.push('Decent rating'); }

  // Has website = cares about presence (0-15)
  if (lead.website) {
    score += 15;
    signals.push('Has website');

    // Check for booking keywords on website (basic heuristic)
    const website = lead.website.toLowerCase();
    if (website.includes('book') || website.includes('schedule') || website.includes('appointment')) {
      score -= 10; // Already has some booking system
      signals.push('May have booking already (check)');
    }
  } else {
    score += 20; // No website = bigger opportunity
    signals.push('NO website - high friction');
  }

  // Phone listed but no online booking = friction (0-20)
  if (lead.phone && !lead.website) {
    score += 20;
    signals.push('Phone only - high friction');
  } else if (lead.phone) {
    score += 10;
    signals.push('Phone listed');
  }

  // Category fit (0-15)
  const highValueCategories = ['Salon/Barber', 'Auto Shop', 'Contractor', 'Plumber', 'Electrician', 'Roofer'];
  if (highValueCategories.includes(lead.category)) {
    score += 15;
    signals.push('High-value category');
  } else {
    score += 10;
    signals.push('Service category');
  }

  // Cap at 100
  score = Math.min(score, 100);

  // Determine stage
  let stage = 'New';
  if (score >= 80) stage = 'Hot';
  else if (score >= 65) stage = 'Warm';
  else if (score >= 50) stage = 'Qualified';

  lead.score = score;
  lead.stage = stage;
  lead.signals = signals.join('; ');
  lead.created_date = new Date().toISOString();
  lead.owner = 'Phillip';
  lead.source = 'Google Maps Service Scraper';

  scored.push({ json: lead });
}

return scored;

const items = items || .all();
const hot = [];
const warm = [];
const other = [];

for (const item of items) {
  const lead = item.json;
  if (lead.score >= 80) hot.push(item);
  else if (lead.score >= 65) warm.push(item);
  else other.push(item);
}

// Save to SQLite for CRM
const fs = require('fs');
const dbPath = '/home/node/.n8n-files/sybridge-crm.db';

// Return summary
const summary = {
  total: items.length,
  hot: hot.length,
  warm: warm.length,
  other: other.length,
  top_leads: hot.slice(0, 5).map(l => ({ name: l.json.name, score: l.json.score, category: l.json.category }))
};

return [{ json: summary, all_leads: items }];

